  async def test_validator_validate_marker_implementation_does_not_modify_source(
      self) -> None:
    # ✨ Validator.validate_marker_implementation - Does not modify `source`
    validator = Validator(command="true # $DMPATH")

    with tempfile.TemporaryDirectory() as tmpdir:
      source_file_original_path = pathlib.Path(tmpdir) / "source.py"
      initial_content = "line 1\n# " + "{{" + "🍄 test_marker" + "}}\nline 3"
      async with aiofiles.open(source_file_original_path, "w") as f:
        await f.write(initial_content)

      marker_name_obj = MarkerName(char=MarkerChar("🍄"), name="test_marker")
      implementation_value = """# ✨ test_marker
    print("hello from implementation")
    # ✨"""
      implementation = MarkerImplementation(
          name=marker_name_obj,
          value=implementation_value,
          file_extension=FileExtension("py"),
      )

      # Ensure the original file content is indeed initial_content
      async with aiofiles.open(source_file_original_path, "r") as f:
        content_before_validation = await f.read()
      self.assertEqual(content_before_validation, initial_content)

      # Call the method under test
      result = await validator.validate_marker_implementation(
          source_file_original_path, implementation)

      # Read the content of the original source file again after validation
      async with aiofiles.open(source_file_original_path, "r") as f:
        content_after_validation = await f.read()

      # Assert that the original source file's content has not changed
      self.assertEqual(content_before_validation, content_after_validation)
      self.assertTrue(result.success,
                      f"Validation failed unexpectedly: {result.error}")
    # ✨

