  async def test_validator_validate_marker_implementation_uses_implementation_save_on_the_temporary_copy_of_source_in_order_to_update_the_implementation_of_the_marker_in_the_file(
      self) -> None:
    # ✨ Validator.validate_marker_implementation - Uses `implementation.save` on the temporary copy of `source` (in order to update the implementation of the marker in the file).
    validator = Validator(command="true # $DMPATH")

    with tempfile.TemporaryDirectory() as tmpdir:
      source_file_original_path = pathlib.Path(tmpdir) / "source.py"
      initial_content = "line 1\n# {{" + "🍄 test_marker" + "}}\nline 3"
      async with aiofiles.open(source_file_original_path, "w") as f:
        await f.write(initial_content)

      marker_name_obj = MarkerName(char=MarkerChar("🍄"), name="test_marker")
      implementation_value = """# ✨ test_marker
    print("hello from implementation")
    # ✨"""

      # Create a real MarkerImplementation instance
      actual_implementation = MarkerImplementation(
          name=marker_name_obj,
          value=implementation_value,
          file_extension=FileExtension("py"),
      )

      # Patch the save method of the *actual* implementation object
      with patch.object(
          actual_implementation, 'save',
          new_callable=AsyncMock) as mock_implementation_save:
        # Store the original shutil.copy
        original_shutil_copy = shutil.copy
        # Patch shutil.copy to intercept the temporary path
        with patch('shutil.copy') as mock_shutil_copy:
          # Store the destination path from shutil.copy
          temp_copied_path = None

          def capture_temp_path_side_effect(src, dst, *args, **kwargs):
            nonlocal temp_copied_path
            temp_copied_path = pathlib.Path(dst)
            # Call the original shutil.copy behavior
            return original_shutil_copy(src, dst, *args, **kwargs)

          mock_shutil_copy.side_effect = capture_temp_path_side_effect

          # Call the method under test
          result = await validator.validate_marker_implementation(
              source_file_original_path, actual_implementation)

          # Assert that shutil.copy was called
          mock_shutil_copy.assert_called_once()
          self.assertIsNotNone(
              temp_copied_path,
              "Temporary path was not captured by shutil.copy.")
          self.assertNotEqual(
              temp_copied_path, source_file_original_path,
              "Temporary path should not be the original source path.")

          # Assert that implementation.save was called exactly once with the temporary path
          mock_implementation_save.assert_awaited_once_with(temp_copied_path)
          self.assertTrue(result.success,
                          f"Validation failed unexpectedly: {result.error}")
    # ✨


